  const ecartGlobal = parseFloat(d.Ecart_Global   || 0);
  const montantBC   = parseFloat(d.MontantBC      || 0);

  // ── RAPPROCHEMENT BC vs FACTURE ─────────────────────────────────
  const deltaBC        = mntFacture - montantBC;        // Facture - BC (ligne individuelle)
  const deltaBCabs     = Math.abs(deltaBC);
  const bcOk           = deltaBCabs <= TOLERANCE_DH;

  // ── RAPPROCHEMENT SOMME BRs vs FACTURE ──────────────────────────
  const deltaSomeBR    = mntFacture - someBRF;          // Facture - Somme BRs
  const deltaSomeBRabs = Math.abs(deltaSomeBR);
  const someBRok       = deltaSomeBRabs <= TOLERANCE_DH;

  // ── RAPPROCHEMENT ÉCART GLOBAL (déjà calculé en amont) ──────────
  const ecartGlobalAbs = Math.abs(ecartGlobal);
  const ecartGlobalOk  = ecartGlobalAbs <= TOLERANCE_DH;

  // ── STATUT GLOBAL ────────────────────────────────────────────────
  // On valide si la somme des BRs couvre la facture à la tolérance près
  // OU si l'écart global calculé est dans la tolérance
  const rapprochementOk = someBRok || ecartGlobalOk;

  // ── CLASSIFICATION DE L'ÉCART ────────────────────────────────────
