    severite = 'FAIBLE';      // Écart ≤ 10 DH
  } else if (ecartGlobalAbs <= 100) {
    severite = 'MOYEN';       // Écart ≤ 100 DH
  } else if (ecartGlobalAbs <= 1000) {
